### Upload Command (`/Users/marc/conductor/workspaces/rudel/medan/apps/cli/src/commands/upload.ts`)

#### Full Content

```typescript
import { buildCommand } from "@stricli/core";
import { classifySession } from "../lib/classifier.js";
import { loadCredentials } from "../lib/credentials.js";
import { getGitInfo } from "../lib/git-info.js";
import { getProjectOrgId } from "../lib/project-config.js";
import { resolveSession } from "../lib/session-resolver.js";
import { readSubagentFiles } from "../lib/subagent-reader.js";
import { extractAgentIds, readTranscript } from "../lib/transcript-reader.js";
import {
	DEFAULT_ENDPOINT,
	type IngestRequest,
	SESSION_TAGS,
	type SessionTag,
	type SubagentFile,
} from "../lib/types.js";
import { uploadSession } from "../lib/uploader.js";

async function runUpload(
	flags: {
		tag?: SessionTag;
		endpoint: string;
		classify: boolean;
		dryRun: boolean;
		org?: string;
	},
	session: string,
): Promise<void> {
	const write = (msg: string) => {
		process.stdout.write(`${msg}\n`);
	};
	const writeError = (msg: string) => {
		process.stderr.write(`${msg}\n`);
	};

	// Load credentials
	const credentials = loadCredentials();
	if (!credentials && !flags.dryRun) {
		writeError("Error: Not authenticated. Run `rudel login` first.");
		process.exitCode = 1;
		return;
	}

	// Resolve session (by ID or path)
	write(`Resolving session: ${session}`);
	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
	try {
		sessionInfo = await resolveSession(session);
	} catch (error) {
		writeError(
			`Error: ${error instanceof Error ? error.message : String(error)}`,
		);
		process.exitCode = 1;
		return;
	}
	write(`Found session at: ${sessionInfo.transcriptPath}`);

	// Read transcript
	write("Reading transcript...");
	let content: string;
	try {
		content = await readTranscript(sessionInfo.transcriptPath);
	} catch (error) {
		writeError(
			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
		);
		process.exitCode = 1;
		return;
	}
	write(`Transcript: ${content.length} bytes`);

	// Extract and read subagents
	const agentIds = extractAgentIds(content);
	let subagents: SubagentFile[] = [];
	if (agentIds.length > 0) {
		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
		subagents = await readSubagentFiles(
			sessionInfo.sessionDir,
			agentIds,
			sessionInfo.sessionId,
		);
		write(
			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
		);
	}

	// Get git info
	const gitInfo = await getGitInfo(sessionInfo.projectPath);
	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);

	// Classify if requested
	let tag = flags.tag;
	if (!tag && flags.classify) {
		write("Classifying session...");
		tag = (await classifySession(content)) ?? undefined;
		if (tag) write(`Classified as: ${tag}`);
	}

	// Resolve organization
	const organizationId =
		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
	if (organizationId) write(`Organization: ${organizationId}`);

	// Build request
	const request: IngestRequest = {
		sessionId: sessionInfo.sessionId,
		projectPath: sessionInfo.projectPath,
		repository: gitInfo.repository,
		gitBranch: gitInfo.branch,
		gitSha: gitInfo.sha,
		tag,
		content,
		subagents: subagents.length > 0 ? subagents : undefined,
		organizationId,
	};

	// Upload or dry-run
	if (flags.dryRun) {
		const preview = {
			...request,
			content: `[${request.content.length} bytes]`,
			subagents: request.subagents?.map((s) => ({
				...s,
				content: `[${s.content.length} bytes]`,
			})),
		};
		write("Dry run - would upload:");
		write(JSON.stringify(preview, null, 2));
		return;
	}

	write("Uploading...");
	const result = await uploadSession(request, {
		endpoint: flags.endpoint,
		token: credentials!.token,
	});

	if (result.success) {
		write("Upload successful!");
	} else {
		writeError(`Upload failed: ${result.error}`);
		process.exitCode = 1;
	}
}

export const uploadCommand = buildCommand({
	loader: async () => ({ default: runUpload }),
	parameters: {
		positional: {
			kind: "tuple",
			parameters: [
				{
					brief: "Session ID or path to a session .jsonl file",
					parse: String,
					placeholder: "session",
				},
			],
		},
		flags: {
			tag: {
				kind: "enum",
				values: [...SESSION_TAGS],
				brief: "Session tag/category",
				optional: true,
			},
			endpoint: {
				kind: "parsed",
				parse: String,
				brief: "Override the upload endpoint URL",
				default: DEFAULT_ENDPOINT,
			},
			classify: {
				kind: "boolean",
				brief: "Auto-classify session tag using Claude CLI",
				default: false,
			},
			dryRun: {
				kind: "boolean",
				brief: "Preview what would be uploaded without sending",
				default: false,
			},
			org: {
				kind: "parsed",
				parse: String,
				brief: "Override the organization ID to upload to",
				optional: true,
			},
		},
		aliases: {
			t: "tag",
			c: "classify",
			n: "dryRun",
			o: "org",
		},
	},
	docs: {
		brief: "Upload a Claude Code session transcript to the backend",
	},
});
```

#### Command Signature

The `runUpload` function at line 18 accepts:
- `flags` object: `tag?` (SessionTag enum), `endpoint` (string, defaults to `https://app.rudel.ai/rpc`), `classify` (boolean, default false), `dryRun` (boolean, default false), `org?` (string)
- `session` positional argument: a session ID or path to a `.jsonl` file

The Stricli `buildCommand` at line 147 defines this as a **tuple positional** with exactly one required parameter (`session`). There are aliases: `-t` for `--tag`, `-c` for `--classify`, `-n` for `--dry-run`, `-o` for `--org`.

#### Data Flow Through Upload

1. **Credential check** (lines 36-41): Loads from `~/.rudel/credentials.json`. Skipped if `--dry-run`.
2. **Session resolution** (lines 44-54): Calls `resolveSession(session)` which returns `{ transcriptPath, projectPath, sessionDir, sessionId }`.
3. **Transcript reading** (lines 57-69): `readTranscript()` with retry logic (5 attempts, 500ms delay).
4. **Subagent extraction** (lines 72-84): Parses JSONL for `toolUseResult.agentId` entries, then reads subagent files from disk.
5. **Git info** (lines 87-89): Gets repository name, branch, SHA from the project directory.
6. **Classification** (lines 92-97): If `--classify` flag is set and no `--tag`, runs `claude` CLI with a Haiku model to classify the transcript.
7. **Organization resolution** (lines 100-102): Uses `--org` flag, or falls back to `getProjectOrgId()` which reads `~/.rudel/projects.json`.
8. **Request build** (lines 105-115): Assembles `IngestRequest`.
9. **Upload or dry-run** (lines 118-144): Either prints JSON preview or calls `uploadSession()` via oRPC.

