### Session Resolver (`/Users/marc/conductor/workspaces/rudel/medan/apps/cli/src/lib/session-resolver.ts`)

#### Full Content

```typescript
import { readdir, stat } from "node:fs/promises";
import { homedir } from "node:os";
import { basename, dirname, join } from "node:path";

const SESSIONS_BASE_DIR = join(homedir(), ".claude", "projects");

export interface SessionInfo {
	transcriptPath: string;
	projectPath: string;
	sessionDir: string;
	sessionId: string;
}

/**
 * Resolve a session from either a session ID or a full file path.
 * Validates that the file is a main session (not a subagent file).
 */
export async function resolveSession(input: string): Promise<SessionInfo> {
	const isPath = input.includes("/") || input.endsWith(".jsonl");

	if (isPath) {
		return resolveFromPath(input);
	}
	return resolveFromId(input);
}

async function resolveFromPath(filePath: string): Promise<SessionInfo> {
	const filename = basename(filePath);
	validateNotSubagent(filename);

	const file = Bun.file(filePath);
	if (!(await file.exists())) {
		throw new Error(`Session file not found: ${filePath}`);
	}

	const sessionId = filename.replace(/\.jsonl$/, "");
	const sessionDir = dirname(filePath);

	// Walk up from sessionDir to find the project directory name
	// Sessions live at: ~/.claude/projects/<encoded-project-dir>/<sessionId>.jsonl
	const parentDir = basename(sessionDir);
	const projectPath = await decodeProjectPath(parentDir);

	return { transcriptPath: filePath, projectPath, sessionDir, sessionId };
}

async function resolveFromId(sessionId: string): Promise<SessionInfo> {
	validateNotSubagent(`${sessionId}.jsonl`);
	const sessionFileName = `${sessionId}.jsonl`;

	let projectDirs: string[];
	try {
		projectDirs = await readdir(SESSIONS_BASE_DIR);
	} catch {
		throw new Error(`Session not found: ${sessionId}`);
	}

	for (const projectDir of projectDirs) {
		const sessionDir = join(SESSIONS_BASE_DIR, projectDir);
		try {
			const files = await readdir(sessionDir);
			if (files.includes(sessionFileName)) {
				const transcriptPath = join(sessionDir, sessionFileName);
				const projectPath = await decodeProjectPath(projectDir);
				return {
					transcriptPath,
					projectPath,
					sessionDir,
					sessionId,
				};
			}
		} catch {}
	}

	throw new Error(`Session not found: ${sessionId}`);
}

function validateNotSubagent(filename: string): void {
	if (filename.startsWith("agent-") && filename.endsWith(".jsonl")) {
		throw new Error(
			"This is a subagent file, not a main session. Please provide the main session ID or path.",
		);
	}
}

/**
 * Decode an encoded project directory name back to the actual filesystem path.
 * Handles directory names that contain dashes by checking if paths exist.
 *
 * Example: "-Users-marc-Workspace-claude-marketplace" -> "/Users/marc/Workspace/claude-marketplace"
 */
async function decodeProjectPath(encodedDir: string): Promise<string> {
	const parts = encodedDir.replace(/^-/, "").split("-");

	async function findPath(
		partIndex: number,
		currentPath: string,
	): Promise<string | null> {
		if (partIndex >= parts.length) {
			try {
				await stat(currentPath);
				return currentPath;
			} catch {
				return null;
			}
		}

		for (let endIndex = parts.length; endIndex > partIndex; endIndex--) {
			const segment = parts.slice(partIndex, endIndex).join("-");
			const testPath = currentPath
				? `${currentPath}/${segment}`
				: `/${segment}`;

			try {
				await stat(testPath);
				if (endIndex === parts.length) {
					return testPath;
				}
				const result = await findPath(endIndex, testPath);
				if (result) {
					return result;
				}
			} catch {
				// Path doesn't exist, try shorter segment
			}
		}

		return null;
	}

	const result = await findPath(0, "");
	if (result) {
		return result;
	}

	// Fallback: simple dash-to-slash replacement
	return `/${parts.join("/")}`;
}
```

#### Core Logic: `resolveSession` (line 18)

The function dispatches on a heuristic at line 19: if the `input` contains `/` or ends with `.jsonl`, it is treated as a file path; otherwise as a session ID.

#### Path Resolution: `resolveFromPath` (lines 27-44)

1. Extracts `filename` via `basename(filePath)` (line 28).
2. Validates it is not a subagent file (line 29).
3. Checks file existence with `Bun.file(filePath).exists()` (lines 31-33).
4. Derives `sessionId` by stripping `.jsonl` (line 36).
5. Gets `sessionDir` as `dirname(filePath)` (line 37).
6. Gets `parentDir` (the encoded project directory name) via `basename(sessionDir)` (line 41).
7. Calls `decodeProjectPath(parentDir)` to recover the actual filesystem path (line 42).

#### ID Resolution: `resolveFromId` (lines 46-76)

1. Validates it is not a subagent ID (line 47).
2. Reads all directories under `~/.claude/projects/` (line 53).
3. Iterates each project directory, reads its files, and checks if `{sessionId}.jsonl` exists (lines 58-73).
4. On match, calls `decodeProjectPath(projectDir)` to get the project path.
5. Returns the first match found. If no match, throws "Session not found".

#### `decodeProjectPath` (lines 92-138)

This is a recursive path-reconstruction algorithm. Claude Code stores sessions in directories named with the project's absolute path but with `/` replaced by `-` (and a leading `-`). For example, `/Users/marc/Workspace/claude-marketplace` becomes `-Users-marc-Workspace-claude-marketplace`.

The ambiguity arises because directory names can also contain literal dashes (e.g., `claude-marketplace`). The algorithm:

1. Strips the leading `-` and splits on `-` to get `parts` (line 93).
2. Recursively tries to reconstruct the path using `findPath(partIndex, currentPath)` (lines 95-129).
3. At each step, it tries the **longest possible segment first** (greedy approach, `endIndex` counts down from `parts.length` at line 108), joining consecutive parts with `-` to form a candidate segment.
4. For each candidate segment, it builds a test path (prepending `/` if it is the first segment, or appending to `currentPath` with `/`).
5. It checks if the test path exists on disk via `stat()` (line 114).
6. If the test path exists and consumes all remaining parts (`endIndex === parts.length`), it returns immediately (line 116).
7. If the test path exists but there are more parts, it recurses with the remaining parts (line 119).
8. If no valid reconstruction is found, falls back to naive dash-to-slash replacement (line 137): `/${parts.join("/")}`.

